CREATE TABLE IF NOT EXISTS public.blocked_times ( id uuid DEFAULT gen_random_uuid() PRIMARY KEY, location text NOT NULL, date_time timestamptz NOT NULL, specialty text NOT NULL, professional_name text NOT NULL, reason text, created_at timestamptz DEFAULT now() ); ALTER TABLE public.blocked_times ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "Enable read access for all users" ON public.blocked_times; CREATE POLICY "Enable read access for all users" ON public.blocked_times FOR SELECT USING (true); DROP POLICY IF EXISTS "Enable insert for authenticated users only" ON public.blocked_times; CREATE POLICY "Enable insert for authenticated users only" ON public.blocked_times FOR INSERT TO authenticated WITH CHECK (true); DROP POLICY IF EXISTS "Enable delete for authenticated users only" ON public.blocked_times; CREATE POLICY "Enable delete for authenticated users only" ON public.blocked_times FOR DELETE TO authenticated USING (true);
